async function s(a,t,i="signed_document.pdf"){const o=await fetch(`/api/upload-pdf?filename=${encodeURIComponent(i)}`,{method:"POST",headers:{"Content-Type":"application/octet-stream"},body:new Blob([t],{type:"application/pdf"})});if(!o.ok)throw new Error(`Upload failed (HTTP ${o.status})`);const{rid:e}=await o.json();console.log(`📎 Uploaded → attachment RID: ${e}`);const n=await fetch("/api/attach-to-object",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({objectPrimaryKey:a,attachmentRid:e})});if(!n.ok){const c=await n.json().catch(()=>({}));throw new Error(`Failed to link attachment to object (HTTP ${n.status}): ${JSON.stringify(c)}`)}return console.log(`✅ Files[${a}].attachment → ${e}`),e}async function d(a){const t=await fetch(`/api/attachment-metadata?rid=${encodeURIComponent(a)}`);if(!t.ok)throw new Error(`Failed to get attachment (HTTP ${t.status})`);return await t.json()}export{s as attachSignedPdfToFileObject,d as getAttachment};
